import React, { useEffect, useState } from 'react';
import { useAuth } from '../context/AuthContext';
import { leavesAPI, leaveBalanceAPI, aiAgentsAPI, employeesAPI } from '../services/api';
import {
  PageHeader, Card, Table, Btn, Modal, Input, Select, Textarea, Badge, Tabs, toast,
} from '../components/ui';
import { Plus, X, Check, Edit2 } from 'lucide-react';

const STATUS_BADGE = {
  pending:         { variant: 'warning', label: 'Pending' },
  approved_by_hod: { variant: 'info',    label: 'HOD Approved' },
  approved:        { variant: 'success', label: 'Approved' },
  rejected:        { variant: 'danger',  label: 'Rejected' },
  cancelled:       { variant: 'neutral', label: 'Cancelled' },
};

export default function Leaves() {
  const { hasRole } = useAuth();
  const [tab, setTab] = useState('my');
  const [myLeaves, setMyLeaves] = useState([]);
  const [allLeaves, setAllLeaves] = useState([]);
  const [balances, setBalances] = useState([]);
  const [policies, setPolicies] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showApply, setShowApply] = useState(false);
  const [applying, setApplying] = useState(false);
  const [editLeave, setEditLeave] = useState(null);
  const [editing, setEditing] = useState(false);
  const [form, setForm] = useState({ leave_type: 'casual', start_date: '', end_date: '', reason: '' });

  const [showOverride, setShowOverride] = useState(false);
  const [overrideForm, setOverrideForm] = useState({ employee_id: '', leave_type: 'casual', total_days: 0 });
  const [empList, setEmpList] = useState([]);

  const [aiLoading, setAiLoading] = useState(false);
  const [aiRecommendation, setAiRecommendation] = useState('');

  const isHR = hasRole('hr');
  const isHOD = hasRole('department_head');
  const isAdmin = hasRole('admin');
  const canManage = isHR || isHOD || isAdmin;

  const tabs = [
    { key: 'my', label: 'My Leaves' },
    ...(isHOD ? [{ key: 'manage', label: 'Team Requests' }] : []),
    ...(isHR || isAdmin ? [{ key: 'manage', label: 'All Requests' }, { key: 'policies', label: 'Leave Policies' }] : []),
  ];

  const loadData = async () => {
    setLoading(true);
    try {
      const [myRes, balRes] = await Promise.all([
        leavesAPI.myLeaves(),
        leaveBalanceAPI.myBalance().catch(() => ({ data: [] })),
      ]);
      setMyLeaves(myRes.data);
      setBalances(balRes.data || []);

      if (canManage) {
        try {
          let data;
          if (isHR) {
            const [queueRes, polRes, empsRes] = await Promise.all([
              leavesAPI.hrQueue(),
              leaveBalanceAPI.getPolicies().catch(() => ({ data: [] })),
              employeesAPI.list().catch(() => ({ data: [] }))
            ]);
            data = queueRes.data;
            setPolicies(polRes.data || []);
            setEmpList(empsRes.data || []);
          } else if (isHOD) {
            const res = await leavesAPI.hodPending();
            data = res.data;
          }
          setAllLeaves(data || []);
        } catch {
          setAllLeaves([]);
        }
      }
    } catch (e) {
      toast(e.response?.data?.detail || 'Failed to load leaves', 'error');
    } finally {
      setLoading(false);
    }
  };

  // eslint-disable-next-line react-hooks/exhaustive-deps
  useEffect(() => { loadData(); }, []);

  const handleApply = async (e) => {
    e.preventDefault();
    setApplying(true);
    try {
      await leavesAPI.apply(form);
      toast('Leave applied successfully', 'success');
      setShowApply(false);
      setForm({ leave_type: 'casual', start_date: '', end_date: '', reason: '' });
      loadData();
    } catch (e) {
      const errMessage = e.response?.data?.detail;
      if (errMessage?.includes('balance record not found')) {
        toast('Leave system configuration pending. Please contact HR to set up your balances.', 'error');
      } else {
        toast(errMessage || 'Failed to submit leave application. Please check your inputs.', 'error');
      }
    } finally {
      setApplying(false);
    }
  };

  const handleCancel = async (id) => {
    try {
      await leavesAPI.cancel(id);
      toast('Leave cancelled', 'success');
      loadData();
    } catch (e) {
      toast(e.response?.data?.detail || 'Failed to cancel leave', 'error');
    }
  };

  const handleAction = async (leaveId, action) => {
    try {
      if (isHR) {
        await leavesAPI.hrProcess(leaveId, action);
      } else if (isHOD) {
        if (action === 'approve') await leavesAPI.hodApprove(leaveId);
        else await leavesAPI.hodReject(leaveId);
      }
      toast(`Leave ${action}d successfully`, 'success');
      loadData();
    }
    catch(e) {
      toast(e.response?.data?.detail || `Failed to ${action} leave`, 'error');
    }
  };

  const handleEditSubmit = async (e) => {
    e.preventDefault();
    setEditing(true);
    try {
      await leavesAPI.hrUpdate(editLeave.id, {
        start_date: editLeave.start_date,
        end_date: editLeave.end_date,
        reason: editLeave.reason,
      });
      toast('Leave record updated successfully', 'success');
      setEditLeave(null);
      loadData();
    } catch (e) {
      toast(e.response?.data?.detail || 'Failed to update leave', 'error');
    } finally {
      setEditing(false);
    }
  };

  const handleUpdatePolicy = async (e, policyData) => {
    e.preventDefault();
    try {
      await leaveBalanceAPI.updatePolicies(policyData);
      toast('Global leave policy updated', 'success');
      loadData();
    } catch(e) {
      toast(e.response?.data?.detail || 'Failed to update policy', 'error');
    }
  };

  const handleOverride = async (e) => {
    e.preventDefault();
    try {
      await leaveBalanceAPI.hrOverride(overrideForm.employee_id, overrideForm.leave_type, parseInt(overrideForm.total_days));
      toast('Quota overridden successfully', 'success');
      setShowOverride(false);
      setOverrideForm({ employee_id: '', leave_type: 'casual', total_days: 0 });
      loadData();
    } catch(e) {
      toast(e.response?.data?.detail || 'Failed to override quota', 'error');
    }
  };

  const handleRecommendLeave = async () => {
    if (!form.start_date || !form.end_date) {
      toast('Please select start and end dates first', 'warning');
      return;
    }
    setAiLoading(true);
    setAiRecommendation('');
    try {
      const { data } = await aiAgentsAPI.recommendLeave({ start_date: form.start_date, end_date: form.end_date });
      setAiRecommendation(data.result);
    } catch (e) {
      toast(e.response?.data?.detail || 'AI check failed', 'error');
    } finally {
      setAiLoading(false);
    }
  };

  const myCols = [
    { key: 'leave_type', label: 'Type', render: (r) => (
      <span style={{ textTransform: 'capitalize', fontWeight: 500 }}>{r.leave_type}</span>
    )},
    { key: 'start_date', label: 'Start Date' },
    { key: 'end_date', label: 'End Date' },
    { key: 'reason', label: 'Reason', render: (r) => (
      <span style={{ maxWidth: 200, display: 'inline-block' }} className="truncate">{r.reason}</span>
    )},
    { key: 'status', label: 'Status', render: (r) => {
      const s = STATUS_BADGE[r.status] || STATUS_BADGE.pending;
      return <Badge variant={s.variant}>{s.label}</Badge>;
    }},
    { key: 'actions', label: '', render: (r) =>
      r.status === 'pending' ? (
        <Btn variant="ghost" size="xs" onClick={() => handleCancel(r.id)} style={{ color: 'var(--danger)' }}>
          <X size={14} /> Cancel
        </Btn>
      ) : null
    },
  ];

  const manageCols = [
    { key: 'employee_id', label: 'Emp ID' },
    { key: 'leave_type', label: 'Type', render: (r) => (
      <span style={{ textTransform: 'capitalize', fontWeight: 500 }}>{r.leave_type}</span>
    )},
    { key: 'start_date', label: 'Start' },
    { key: 'end_date', label: 'End' },
    { key: 'reason', label: 'Reason', render: (r) => (
      <span style={{ maxWidth: 180, display: 'inline-block' }} className="truncate">{r.reason}</span>
    )},
    { key: 'status', label: 'Status', render: (r) => {
      const s = STATUS_BADGE[r.status] || STATUS_BADGE.pending;
      return <Badge variant={s.variant}>{s.label}</Badge>;
    }},
    { key: 'actions', label: 'Actions', render: (r) => {
      const canApprove =
        (isHOD && r.status === 'pending') ||
        (isHR && (r.status === 'approved_by_hod' || r.status === 'pending')) ||
        (isAdmin && (r.status === 'pending' || r.status === 'approved_by_hod'));

      if (!canApprove && !isHR && !isAdmin) return null;
      return (
        <div style={{ display: 'flex', gap: 6 }}>
          {canApprove && (
            <>
              <Btn variant="success" size="xs" onClick={() => handleAction(r.id, 'approve')}>
                <Check size={13} /> Approve
              </Btn>
              <Btn variant="danger" size="xs" onClick={() => handleAction(r.id, 'reject')}>
                <X size={13} /> Reject
              </Btn>
            </>
          )}
          {isHR && (
            <Btn variant="secondary" size="xs" onClick={() => setEditLeave(r)}>
              <Edit2 size={13} /> Edit
            </Btn>
          )}
        </div>
      );
    }},
  ];

  return (
    <>
      <PageHeader
        title="Leave Management"
        subtitle="Apply for leave and manage leave requests"
        actions={
          <div style={{ display: 'flex', gap: 8 }}>
            {isHR && (
              <Btn variant="outline" onClick={() => setShowOverride(true)}>
                Quota Override
              </Btn>
            )}
            <Btn onClick={() => setShowApply(true)}>
              <Plus size={16} /> Apply Leave
            </Btn>
          </div>
        }
      />

      {/* Leave Balance Cards */}
        <div style={{ marginBottom: 24 }}>
          <div className="grid-stats">
            {balances.map((b) => (
              <Card key={b.leave_type} style={{ padding: 18 }}>
                <div style={{ textTransform: 'capitalize', fontWeight: 600, fontSize: 14, marginBottom: 8, color: 'var(--text-dark)' }}>
                  {b.leave_type} Leave
                </div>
                <div style={{ display: 'flex', alignItems: 'baseline', gap: 6 }}>
                  {b.leave_type === 'unpaid' ? (
                    <>
                      <span style={{ fontSize: 24, fontWeight: 700, color: 'var(--gray-600)' }}>Unlimited</span>
                      <span style={{ fontSize: 13, color: 'var(--gray-500)' }}>(Tracked)</span>
                    </>
                  ) : (
                    <>
                      <span style={{ fontSize: 28, fontWeight: 700, color: 'var(--primary)' }}>{b.remaining_days}</span>
                      <span style={{ fontSize: 13, color: 'var(--gray-500)' }}>/ {b.total_days} days remaining</span>
                    </>
                  )}
                </div>
                {b.leave_type !== 'unpaid' && (
                  <div style={{ height: 4, background: 'var(--gray-200)', borderRadius: 2, marginTop: 10, overflow: 'hidden' }}>
                    <div
                      style={{
                        height: '100%',
                        width: `${b.total_days > 0 ? ((b.remaining_days / b.total_days) * 100) : 0}%`,
                        background: b.remaining_days <= 2 ? 'var(--danger)' : 'var(--primary)',
                        borderRadius: 2,
                        transition: 'width 0.3s ease',
                      }}
                    />
                  </div>
                )}
              </Card>
            ))}
          </div>
          {/* Predictor Engine Tip */}
          <div style={{ marginTop: 12, padding: '12px 16px', background: 'var(--info-bg, #eff6ff)', borderRadius: 8, border: '1px solid #bfdbfe', display: 'flex', alignItems: 'center', gap: 8 }}>
            <span style={{ fontSize: 16 }}>💡</span>
            <span style={{ fontSize: 13, color: '#1e40af', fontWeight: 500 }}>
              {balances.find(b => b.leave_type === 'casual')?.remaining_days > 4 
                ? 'Tip: You have plenty of Casual leaves saved up! Booking a Friday off this month keeps your balance healthy for winter.' 
                : 'Tip: You are running low on Casual leaves. Save your remaining days for emergencies!'}
            </span>
          </div>
        </div>

      <Card style={{ padding: 0, overflow: 'hidden' }}>
        <div style={{ padding: '16px 20px 0' }}>
          <Tabs tabs={tabs} active={tab} onChange={setTab} />
        </div>

        {tab === 'my' && <Table cols={myCols} rows={myLeaves} loading={loading} emptyMsg="No leave records found" />}
        {tab === 'manage' && <Table cols={manageCols} rows={allLeaves} loading={loading} emptyMsg="No leave requests to manage" />}
        {tab === 'policies' && (
          <div style={{ padding: '0 20px 20px' }}>
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))', gap: '16px' }}>
              {['faculty', 'accountant', 'employee'].map((roleType) => (
                <div key={roleType} style={{ border: '1px solid var(--border-color)', borderRadius: '8px', padding: '16px', background: 'var(--bg-card)' }}>
                  <h4 style={{ textTransform: 'capitalize', marginBottom: '12px', color: 'var(--text-dark)', fontWeight: 600 }}>{roleType} Policies</h4>
                  {policies.filter(p => p.role_name === roleType).length === 0 && (
                    <div style={{ fontSize: 13, color: 'var(--text-light)' }}>No active mapping for this role</div>
                  )}
                  {policies.filter(p => p.role_name === roleType).map(p => (
                    <form key={p.id} onSubmit={(e) => handleUpdatePolicy(e, { role_name: p.role_name, leave_type: p.leave_type, default_days: e.target.elements.days.value })} style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '8px', background: 'var(--gray-50)', padding: '8px', borderRadius: '4px' }}>
                      <span style={{ textTransform: 'capitalize', fontSize: '14px', fontWeight: 500 }}>{p.leave_type} Leave</span>
                      <div style={{ display: 'flex', gap: '8px' }}>
                        <input name="days" type="number" min="0" defaultValue={p.default_days} style={{ width: '60px', padding: '4px 8px', borderRadius: '4px', border: '1px solid var(--border-color)' }} />
                        <Btn type="submit" size="xs">Save</Btn>
                      </div>
                    </form>
                  ))}
                  {/* Provide base form for missing defaults if hr wants to create them */}
                  <div style={{ marginTop: '16px', paddingTop: '16px', borderTop: '1px solid var(--border-color)' }}>
                    <form onSubmit={(e) => { e.preventDefault(); handleUpdatePolicy(e, { role_name: roleType, leave_type: e.target.elements.type.value, default_days: e.target.elements.days.value }); e.target.reset(); }} style={{ display: 'flex', gap: '8px' }}>
                      <select name="type" style={{ padding: '4px', borderRadius: '4px', border: '1px solid var(--border-color)', flex: 1 }}>
                        <option value="casual">Casual</option>
                        <option value="sick">Sick</option>
                        <option value="earned">Earned</option>
                        <option value="unpaid">Unpaid</option>
                      </select>
                      <input name="days" type="number" min="0" placeholder="0" style={{ width: '60px', padding: '4px 8px', borderRadius: '4px', border: '1px solid var(--border-color)' }} required />
                      <Btn type="submit" size="xs" variant="outline"><Plus size={14}/></Btn>
                    </form>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}
      </Card>

      {/* Apply Leave Modal */}
      <Modal open={showApply} onClose={() => setShowApply(false)} title="Apply for Leave">
        <form onSubmit={handleApply}>
          <Select
            label="Leave Type"
            value={form.leave_type}
            onChange={(e) => setForm({ ...form, leave_type: e.target.value })}
            id="leave-type"
          >
            <option value="casual">Casual</option>
            <option value="sick">Sick</option>
            <option value="earned">Earned</option>
            <option value="unpaid">Unpaid</option>
          </Select>
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '0 16px' }}>
            <Input
              label="Start Date"
              type="date"
              value={form.start_date}
              onChange={(e) => setForm({ ...form, start_date: e.target.value })}
              required
              id="leave-start"
            />
            <Input
              label="End Date"
              type="date"
              value={form.end_date}
              min={form.start_date}
              onChange={(e) => setForm({ ...form, end_date: e.target.value })}
              required
              id="leave-end"
            />
          </div>
          <div style={{ margin: '12px 0' }}>
            <Btn type="button" variant="ghost" size="sm" onClick={handleRecommendLeave} loading={aiLoading}>
              <span style={{ marginRight: 6 }}>✨</span> AI Optimal Dates
            </Btn>
            {aiRecommendation && (
              <div style={{ padding: '8px 12px', background: 'var(--gray-50)', borderRadius: 4, marginTop: 8, fontSize: 13, border: '1px solid var(--border-color)', color: 'var(--text-light)', lineHeight: 1.5 }}>
                {aiRecommendation}
              </div>
            )}
          </div>
          <Textarea
            label="Reason"
            value={form.reason}
            onChange={(e) => setForm({ ...form, reason: e.target.value })}
            placeholder="Provide a reason for your leave"
            required
            id="leave-reason"
          />
          <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 10, marginTop: 8 }}>
            <Btn variant="secondary" onClick={() => setShowApply(false)}>Cancel</Btn>
            <Btn type="submit" loading={applying}>Submit Leave</Btn>
          </div>
        </form>
      </Modal>

      {/* HR Edit Leave Modal */}
      {isHR && editLeave && (
        <Modal open={!!editLeave} onClose={() => setEditLeave(null)} title="Edit Leave Record (HR Only)">
          <form onSubmit={handleEditSubmit}>
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '0 16px' }}>
              <Input
                label="Start Date"
                type="date"
                value={editLeave.start_date.split('T')[0]} // Ensure format
                onChange={(e) => setEditLeave({ ...editLeave, start_date: e.target.value })}
                required
                id="edit-leave-start"
              />
              <Input
                label="End Date"
                type="date"
                value={editLeave.end_date.split('T')[0]}
                min={editLeave.start_date.split('T')[0]}
                onChange={(e) => setEditLeave({ ...editLeave, end_date: e.target.value })}
                required
                id="edit-leave-end"
              />
            </div>
            <Textarea
              label="Reason"
              value={editLeave.reason}
              onChange={(e) => setEditLeave({ ...editLeave, reason: e.target.value })}
              required
              id="edit-leave-reason"
            />
            <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 10, marginTop: 8 }}>
              <Btn variant="secondary" onClick={() => setEditLeave(null)}>Cancel</Btn>
              <Btn type="submit" loading={editing}>Update Record</Btn>
            </div>
          </form>
        </Modal>
      )}

      {/* Quota Override Modal */}
      <Modal open={showOverride} onClose={() => setShowOverride(false)} title="Override Employee Quota" width={400}>
        <form onSubmit={handleOverride}>
          <Select label="Employee" value={overrideForm.employee_id} onChange={(e) => setOverrideForm({ ...overrideForm, employee_id: e.target.value })} required id="override-emp">
            <option value="">Select Employee</option>
            {empList.map(e => <option key={e.employee_id || e.id} value={e.id}>{e.first_name} {e.last_name}</option>)}
          </Select>
          <Select label="Leave Type" value={overrideForm.leave_type} onChange={(e) => setOverrideForm({ ...overrideForm, leave_type: e.target.value })} required id="override-type">
            <option value="casual">Casual</option>
            <option value="sick">Sick</option>
            <option value="earned">Earned</option>
            <option value="unpaid">Unpaid</option>
          </Select>
          <Input label="New Total Days" type="number" min="0" value={overrideForm.total_days} onChange={(e) => setOverrideForm({ ...overrideForm, total_days: e.target.value })} required id="override-days" />
          <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 10, marginTop: 16 }}>
            <Btn variant="secondary" type="button" onClick={() => setShowOverride(false)}>Cancel</Btn>
            <Btn type="submit">Save Quota</Btn>
          </div>
        </form>
      </Modal>
    </>
  );
}
